hook.real_world_problem:
Razorpay streaming RPC bug:

```
PaymentConfirmationService.streamConfirmations():
  Sends payment status updates to merchant webhook listener
  Stream: INITIATED → PROCESSING → CONFIRMED/FAILED

Bug: when payment amount > ₹10 lakh, onError() called instead of onNext()
  Merchant connection drops, merchant doesn't receive CONFIRMED
  Merchant retries payment → customer charged twice
  12-minute outage, ₹18 crore impact

Would have been caught by:
  TestStreamObserver observer = new TestStreamObserver<>();
  stub.streamConfirmations(PaymentRequest.newBuilder().setAmount(10_00_001).build(), observer);
  observer.awaitCompletion();
  assertTrue(observer.getValues().stream().anyMatch(r -> r.getStatus().equals("CONFIRMED")));
  // ← TEST WOULD HAVE FAILED for amount > 10L, caught in CI
```

concept_explanation.inprocess_server:
**InProcessServer — gRPC testing without network:**

```java
@ExtendWith(GrpcExtension.class)  // OR manual setup:
class PaymentServiceTest {

    private ManagedChannel channel;
    private Server server;

    @BeforeEach
    void setup() throws IOException {
        String serverName = InProcessServerBuilder.generateName();

        // Start in-process server:
        server = InProcessServerBuilder
            .forName(serverName)
            .directExecutor()    // single-threaded for tests
            .addService(new PaymentServiceImpl())  // real implementation
            .build()
            .start();

        // Connect in-process channel:
        channel = InProcessChannelBuilder
            .forName(serverName)
            .directExecutor()
            .build();
    }

    @AfterEach
    void teardown() throws InterruptedException {
        channel.shutdownNow().awaitTermination(5, TimeUnit.SECONDS);
        server.shutdownNow().awaitTermination(5, TimeUnit.SECONDS);
    }

    @Test void createPayment_returnsPaymentId() {
        PaymentServiceGrpc.PaymentServiceBlockingStub stub =
            PaymentServiceGrpc.newBlockingStub(channel);

        PaymentResponse response = stub.createPayment(
            PaymentRequest.newBuilder()
                .setMerchantId("MRC-001")
                .setAmountPaise(50000)
                .build());

        assertNotNull(response.getPaymentId());
        assertEquals("CREATED", response.getStatus());
    }
}
```

concept_explanation.streaming_test:
**Testing streaming RPCs:**

```java
// TestStreamObserver: captures all messages for assertion
class TestStreamObserver<T> implements StreamObserver<T> {
    private final List<T> values = new CopyOnWriteArrayList<>();
    private Throwable error;
    private final CountDownLatch completed = new CountDownLatch(1);

    @Override public void onNext(T value) { values.add(value); }
    @Override public void onError(Throwable t) { error = t; completed.countDown(); }
    @Override public void onCompleted() { completed.countDown(); }

    public void awaitCompletion() throws InterruptedException {
        assertTrue(completed.await(5, TimeUnit.SECONDS), "Stream did not complete");
    }
    public List<T> getValues() { return values; }
    public Throwable getError() { return error; }
    public boolean hasError() { return error != null; }
}

// Test server-streaming:
@Test void streamPaymentUpdates_sendsAllStatuses() throws InterruptedException {
    PaymentServiceGrpc.PaymentServiceStub asyncStub =
        PaymentServiceGrpc.newStub(channel);

    TestStreamObserver<PaymentUpdate> observer = new TestStreamObserver<>();
    asyncStub.streamPaymentUpdates(
        PaymentRequest.newBuilder().setPaymentId("PAY-001").build(),
        observer);

    observer.awaitCompletion();
    assertFalse(observer.hasError());
    assertEquals(3, observer.getValues().size()); // INITIATED, PROCESSING, CONFIRMED
    assertEquals("CONFIRMED", observer.getValues().get(2).getStatus());
}
```

